import random

CONCEPT_TYPE = "linear_algebra.linear_system_sum"
CONCEPT_GROUP = "algebra"

def generate(seed):
    rng = random.Random(seed)

    # Generate a linear system of equations
    num_equations = rng.randint(2, 4)
    num_variables = rng.randint(2, 4)
    while num_variables <= num_equations:
        num_equations = rng.randint(2, 4)
        num_variables = rng.randint(2, 4)

    # Generate coefficients and constants
    coefficients = [[rng.randint(1, 10) for _ in range(num_variables)] for _ in range(num_equations)]
    constants = [rng.randint(1, 20) for _ in range(num_equations)]

    # Solve the system using Gaussian elimination
    answer = [0] * num_variables
    for i in range(num_equations):
        for j in range(num_variables):
            if j < i:
                coefficients[i][j] = 0
            elif j == i:
                coefficients[i][j] = 1
            else:
                coefficients[i][j] = 0

    for i in range(num_equations):
        for j in range(i + 1, num_equations):
            if coefficients[j][i] != 0:
                factor = coefficients[j][i] / coefficients[i][i]
                for k in range(i, num_variables + 1):
                    coefficients[j][k] -= factor * coefficients[i][k]

    for i in range(num_equations - 1, -1, -1):
        for j in range(i + 1, num_variables):
            if coefficients[i][j] != 0:
                factor = coefficients[i][j] / coefficients[j][j]
                for k in range(i, num_variables + 1):
                    coefficients[i][k] -= factor * coefficients[j][k]
                constants[i] -= factor * constants[j]

    for i in range(num_equations):
        constants[i] /= coefficients[i][i]
        coefficients[i][i] = 1

    for i in range(num_variables):
        answer[i] = constants[i]

    problem = (
        f"Solve the following system of linear equations:\n"
    )
    for i in range(num_equations):
        eq = f"{coefficients[i][0]}x + {coefficients[i][1]}y = {constants[i]}"
        problem += eq + "\n"

    return problem, str(answer)
